import{_ as e,a as i,b as t}from"./chunks/支持留言.NiGCLVdp.js";import{_ as n,o as s,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/blog.md","filePath":"id-ID/Other/blog.md","lastUpdated":1781962217000}'),p={name:"id-ID/Other/blog.md"};function d(g,a,r,u,m,c){return s(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Fitur blog menambahkan halaman blog terpisah ke situs ImgBed Anda.</p><p>Setelah diaktifkan, pengunjung bisa membuka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Blog homepage" loading="lazy"></p><p>Blog ini diadaptasi dari proyek open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed menulis ulang dan mengintegrasikannya dengan Vue agar bisa berjalan sebagai bagian dari situs image hosting.</p><h2 id="lokasi-pengaturan" tabindex="-1">Lokasi Pengaturan <a class="header-anchor" href="#lokasi-pengaturan" aria-label="Permalink to &quot;Lokasi Pengaturan&quot;">​</a></h2><p>Pengaturan blog ada di:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+i+'" alt="Blog settings" loading="lazy"></p><h2 id="setup-pertama-kali" tabindex="-1">Setup Pertama Kali <a class="header-anchor" href="#setup-pertama-kali" aria-label="Permalink to &quot;Setup Pertama Kali&quot;">​</a></h2><ol><li>Aktifkan <code>Enable</code>.</li><li>Pilih akun GitHub yang akan dipakai untuk menyimpan konfigurasi blog.</li><li>Klik <code>Update Blog</code>.</li><li>Tunggu pesan berhasil.</li><li>Buka <code>https://your-domain.com/blog/</code> untuk melihat blog.</li></ol><p>Saat pertama kali dipakai, ImgBed akan menyiapkan repository GitHub private di akun yang dipilih:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Repository ini menyimpan pengaturan blog dan konten artikel.</p><h2 id="menulis-post" tabindex="-1">Menulis Post <a class="header-anchor" href="#menulis-post" aria-label="Permalink to &quot;Menulis Post&quot;">​</a></h2><p>Edit post blog di repository GitHub private Anda:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Alur umumnya:</p><ol><li>Buka GitHub.</li><li>Masuk ke repository private <code>imgbed-blog-config</code>.</li><li>Edit atau tambahkan file post.</li><li>Commit perubahan.</li><li>Kembali ke panel admin ImgBed dan klik <code>Update Blog</code>, atau klik logo di kiri atas homepage blog tiga kali untuk memicu update blog.</li></ol><p><code>Update Blog</code> tidak menimpa konten yang sudah Anda tulis. Tombol ini menginisialisasi repository bila diperlukan dan menyegarkan cache blog.</p><h2 id="fitur-yang-didukung" tabindex="-1">Fitur yang Didukung <a class="header-anchor" href="#fitur-yang-didukung" aria-label="Permalink to &quot;Fitur yang Didukung&quot;">​</a></h2><p>Blog mendukung fitur umum seperti daftar post, kategori, tag, arsip, pencarian, dark mode, dan penggantian bahasa.</p><p>Blog juga mendukung komentar dan statistik kunjungan.</p><p><img src="'+t+'" alt="Blog comments" loading="lazy"></p><p>Komentar muncul di bawah post. Pengunjung bisa mengisi avatar, nickname, email, dan isi komentar.</p><p>Statistik kunjungan menampilkan jumlah view post dan kunjungan situs, sehingga Anda bisa memantau traffic blog.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog selalu disajikan di <code>/blog/</code>.</p><p>Misalnya domain ImgBed Anda:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>Maka URL blog adalah:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Setelah blog dinonaktifkan, pengunjung tidak bisa lagi mengakses halaman blog.</p>',34)])])}const y=n(p,[["render",d]]);export{k as __pageData,y as default};
